1756	\section{The rank-\(e\) stratum as a closed subscheme}
1757	\label{sec:flatstrat_rank_stratum}
1758	
1759	The entry-ideal commutative algebra of \cref{sec:entry_ideal} is local to an
1760	affine chart.  This section globalises it: for a quasi-coherent module
1761	\(\mathcal G\) on a scheme \(X\) it assembles the local entry ideals into a
1762	quasi-coherent ideal sheaf whose closed subscheme --- the \emph{rank-\(e\)
1763	stratum} --- has support exactly the locus where the fibre of \(\mathcal G\)
1764	has dimension \(e\).  This is the geometric substrate of Nitsure's
1765	\(n = 0\) construction (\cref{lem:flat_locus_open}).  Throughout \(X\) is a
1766	scheme and \(\mathcal G\) a quasi-coherent \(\OO_X\)-module; \(\Gamma(\mathcal G, U)\)
1767	denotes its sections over an open \(U\), a module over \(\Gamma(X, U) = \OO_X(U)\).
1768	
1769	\subsection{Base change of the fibre rank}
1770	
1771	\begin{theorem}[Base-change invariance of the fibre rank]
1772	  \label{thm:fiber_rank_base_change}
1773	  \lean{Ideal.fiberRank_baseChange}
1774	  \leanok
1775	  \uses{def:fiber_rank}
1776	  Let \(A\) be an \(R\)-algebra, \(M\) an \(R\)-module, and \(\mathfrak q\) a
1777	  prime of \(A\) with contraction \(\mathfrak p = \mathfrak q \cap R\).  Then
1778	  the fibre rank of \(A \otimes_R M\) at \(\mathfrak q\) equals the fibre rank
1779	  of \(M\) at \(\mathfrak p\).  No flatness or finiteness hypotheses are
1780	  needed.
1781	\end{theorem}
1782	
1783	\begin{proof}
1784	  \leanok
1785	  The residue-field map \(R \to \kappa(\mathfrak p) \to \kappa(\mathfrak q)\)
1786	  makes \(\kappa(\mathfrak q)\) a \(\kappa(\mathfrak p)\)-algebra.  Cancelling
1787	  base changes gives \(\kappa(\mathfrak p)\)-linear, then
1788	  \(\kappa(\mathfrak q)\)-linear, isomorphisms
1789	  \[
1790	    \kappa(\mathfrak q) \otimes_A (A \otimes_R M)
1791	      \;\cong\; \kappa(\mathfrak q) \otimes_R M
1792	      \;\cong\; \kappa(\mathfrak q) \otimes_{\kappa(\mathfrak p)}
1793	        \bigl(\kappa(\mathfrak p) \otimes_R M\bigr).
1794	  \]
1795	  Extension of scalars along a field extension preserves dimension, so
1796	  \(\dim_{\kappa(\mathfrak q)}
1797	    \kappa(\mathfrak q) \otimes_{\kappa(\mathfrak p)}
1798	    (\kappa(\mathfrak p) \otimes_R M)
1799	    = \dim_{\kappa(\mathfrak p)}(\kappa(\mathfrak p) \otimes_R M)\),
1800	  which is the claim.
1801	\end{proof}
1802	
1803	\begin{lemma}[Fibre rank is a linear invariant]
1804	  \label{lem:fiber_rank_congr}
1805	  \lean{Ideal.fiberRank_congr}
1806	  \leanok
1807	  \uses{def:fiber_rank}
1808	  If \(\sigma : M \cong N\) is an isomorphism of \(R\)-modules, then \(M\) and
1809	  \(N\) have the same fibre rank at every prime \(\mathfrak p\).
1810	\end{lemma}
1811	
1812	\begin{proof}
1813	  \leanok
1814	  Base change \(\sigma\) along \(R \to \kappa(\mathfrak p)\) to obtain a
1815	  \(\kappa(\mathfrak p)\)-linear isomorphism
1816	  \(\kappa(\mathfrak p) \otimes_R M \cong \kappa(\mathfrak p) \otimes_R N\);
1817	  isomorphic vector spaces have equal dimension.
1818	\end{proof}
1819	
1820	\begin{corollary}[Fibre rank of a localized module]
1821	  \label{cor:fiber_rank_localized}
1822	  \lean{Ideal.fiberRank_of_isLocalizedModule}
1823	  \leanok
1824	  \uses{thm:fiber_rank_base_change, lem:fiber_rank_congr}
1825	  Let \(R' = S^{-1}R\) be a localization, \(N = S^{-1}M\) the corresponding
1826	  localized module, and \(\mathfrak q\) a prime of \(R'\).  Then the fibre
1827	  rank of \(N\) at \(\mathfrak q\) equals the fibre rank of \(M\) at the
1828	  contraction \(\mathfrak q \cap R\).
1829	\end{corollary}
1830	
1831	\begin{proof}
1832	  \leanok
1833	  Localization is a base change: the canonical map \(M \to N\) induces an
1834	  \(R'\)-linear isomorphism \(R' \otimes_R M \cong N\).  By
1835	  \cref{lem:fiber_rank_congr} the fibre rank of \(N\) at \(\mathfrak q\)
1836	  equals that of \(R' \otimes_R M\), which by \cref{thm:fiber_rank_base_change}
1837	  equals the fibre rank of \(M\) at \(\mathfrak q \cap R\).
1838	\end{proof}
1839	
1840	\subsection{Presentation charts and the point rank}
1841	
1842	\begin{definition}[Presentation chart]
1843	  \label{def:presentation_chart}
1844	  \lean{AlgebraicGeometry.Scheme.Modules.IsPresentationChart}
1845	  \leanok
1846	  \uses{def:matrix_presentation}
1847	  \source{nitsure-hilbert-quot}
1848	  An affine open \(V \subseteq X\) is an \emph{\(e\)-presentation chart} for
1849	  \(\mathcal G\) if the section module \(\Gamma(\mathcal G, V)\) admits a
1850	  matrix presentation by \(e\) generators over \(\Gamma(X, V)\), that is, a
1851	  right-exact sequence
1852	  \(\OO_V^{\oplus m} \xrightarrow{\psi} \OO_V^{\oplus e}
1853	    \to \mathcal G|_V \to 0\).
1854	\end{definition}
1855	
1856	\begin{definition}[Restriction of a presentation to a basic open]
1857	  \label{def:presentation_basic_open}
1858	  \lean{AlgebraicGeometry.Scheme.Modules.MatrixPresentationBasicOpen}
1859	  \leanok
1860	  \uses{def:matrix_presentation_base_change, def:presentation_chart}
1861	  Let \(P = (\psi, \pi)\) be a matrix presentation of
1862	  \(\Gamma(\mathcal G, V)\) by \(e\) generators over an affine open \(V\), and
1863	  \(f \in \Gamma(X, V)\).  Since \(\mathcal G\) is quasi-coherent, restriction
1864	  exhibits \(\Gamma(\mathcal G, D(f))\) as the localization
1865	  \(\Gamma(\mathcal G, V) \otimes_{\Gamma(X, V)} \Gamma(X, D(f))\).  Base
1866	  change of \(P\) along \(\Gamma(X, V) \to \Gamma(X, D(f))\)
1867	  (\cref{def:matrix_presentation_base_change}), transported along this
1868	  localization isomorphism, is a matrix presentation of
1869	  \(\Gamma(\mathcal G, D(f))\) by \(e\) generators, the \emph{restriction of
1870	  \(P\) to \(D(f)\)}; its relation matrix is the entrywise restriction
1871	  \(\psi|_{D(f)}\).
1872	\end{definition}
1873	
1874	\begin{lemma}[Entry ideal of a restricted presentation]
